// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

contract AdmissionEscrow {

    address public student;
    address public teacher;
    uint public fee;

    enum Status { Created, Paid, Released, Refunded }
    Status public status;

    constructor(address _teacher) {
        student = msg.sender;     // student deploys
        teacher = _teacher;
        status = Status.Created;
    }

    // 1️⃣ Student pays fee
    function payFee() public payable {
        require(msg.sender == student, "Only student can pay");
        require(status == Status.Created, "Already paid");
        require(msg.value > 0, "Send some ETH");

        fee = msg.value;
        status = Status.Paid;
    }

    // 2️⃣ Teacher confirms admission → release funds
    function confirmAdmission() public {
        require(msg.sender == teacher, "Only teacher");
        require(status == Status.Paid, "Fee not paid");

        status = Status.Released;
        (bool success, ) = payable(teacher).call{value: fee}("");
        require(success, "Transfer failed");
    }

    // 3️⃣ Teacher rejects → refund
    function rejectAdmission() public {
        require(msg.sender == teacher, "Only teacher");
        require(status == Status.Paid, "Fee not paid");

        status = Status.Refunded;
        (bool success, ) = payable(student).call{value: fee}("");
        require(success, "Transfer failed");
    }
}
